function buscarLinhaDaFonte(fonteStamp, whereFiltros) {
    var fontes = (window.appState && window.appState.fontes) || window.GMDashFontes || [];
    var fonte = fontes.filter(function (f) { return f.mdashfontestamp === fonteStamp; })[0];
    if (!fonte) return null;

    var tbl = mdashFonteTableName(fonte);
    var cfg = MdashTransformBuilder.autoConfig(tbl, 'expr');
    cfg.filters = whereFiltros || [];

    var raw = MdashTransformBuilder.executeRaw(cfg);
    if (raw.error || !raw.rows || !raw.rows.length) return null;

    var linha = {};
    raw.columns.forEach(function (col, i) { linha[col] = raw.rows[0][i]; });
    return linha;
}



function calcularNotaDeKPIDeTeamLeader(estatisticaDoPerformanceDoTecnico, estatisticaDoPerformanceDaEquipa) {
  const pesoDaNotaIndividualDoTeamLeader = 50;
  const pesoDaNotaDaEquipa = 50;

  const notaIndividualDoTeamLeader = calcularNotaDeKPI(estatisticaDoPerformanceDoTecnico);
  const notaDaEquipa = calcularNotaDeKPI(estatisticaDoPerformanceDaEquipa);

  const nota = Math.round(
    (((pesoDaNotaIndividualDoTeamLeader * notaIndividualDoTeamLeader) +
      (pesoDaNotaDaEquipa * notaDaEquipa)) / 100) * 100
  ) / 100; // Math.round em JS não tem parâmetro de casas decimais, por isso multiplicamos/dividimos por 100

  return nota;
}



function calcularNotaDeKPI(estatisticaDoPerformance) {

    const horasEmAssistenciaTecnica = estatisticaDoPerformance["ocpmh"];
    const horasEmProjectos = estatisticaDoPerformance["ocptda"];
    const horasEmMarcacoes = estatisticaDoPerformance["ocpmx"];

    const ocupacaoTotal = horasEmAssistenciaTecnica + horasEmProjectos + horasEmMarcacoes;

    const percentagemDeOcupacaoEmAssistenciaTecnica = horasEmAssistenciaTecnica / (ocupacaoTotal === 0 ? 1 : ocupacaoTotal);
    const percentagemDeOcupacaoEmProjectos = horasEmProjectos / (ocupacaoTotal === 0 ? 1 : ocupacaoTotal);
    const percentagemDeOcupacaoEmMarcacoes = horasEmMarcacoes / (ocupacaoTotal === 0 ? 1 : ocupacaoTotal);

    const notaEmAssistenciaTecnica = calcularNotaDeKPIPorArea("MH", estatisticaDoPerformance) * percentagemDeOcupacaoEmAssistenciaTecnica;
    const notaEmProjectos = calcularNotaDeKPIPorArea("TDA", estatisticaDoPerformance) * percentagemDeOcupacaoEmProjectos;
    const notaEmMarcacoes = calcularNotaDeKPIPorArea("MX", estatisticaDoPerformance) * percentagemDeOcupacaoEmMarcacoes;

    const nota = Math.round(
        (notaEmAssistenciaTecnica + notaEmProjectos + notaEmMarcacoes) * 100
    ) / 100; // equivalente a Math.Round(x, 2)

    return nota;
}



function calcularNotaDeKPIPorArea(area, estatisticaDoPerformance) {

    // ===== Standards (equivalente a GetXxxEsperado() / 100) =====
    const facturabilidadeStandard = 55 / 100;
    const ocupacaoStandard = 80 / 100;
    const patsDentroPrazoStandard = 95 / 100;
    const patsReabertosStandard = 5 / 100;
    const npsStandard = 100 / 100;
    const notaStandard = 10; // não usado no resto do cálculo (tal como no original)

    // ===== Variáveis por área =====
    let horas = 0;
    let facturacao = 0;

    let pesoDeFacturabilidade = 0;
    let pesoDeOcupacao = 0;
    let pesoDePatsDentroDoPrazo = 0;
    let pesoDePatsReabertos = 0;
    let pesoDeNps = 0;

    if (area === "MH") {

        horas = estatisticaDoPerformance["ocpmh"];
        facturacao = estatisticaDoPerformance["ftmh"];

        pesoDeFacturabilidade = 30;
        pesoDeOcupacao = 20;
        pesoDePatsDentroDoPrazo = 30;
        pesoDePatsReabertos = 10;
        pesoDeNps = 10;

    } else if (area === "TDA") {

        horas = estatisticaDoPerformance["ocptda"];
        facturacao = estatisticaDoPerformance["fttda"];

        pesoDeFacturabilidade = 70;
        pesoDeOcupacao = 30;
        pesoDePatsDentroDoPrazo = 0;
        pesoDePatsReabertos = 0;
        pesoDeNps = 0;

    } else if (area === "MX") {

        horas = estatisticaDoPerformance["ocpmx"];
        facturacao = estatisticaDoPerformance["ftmx"];

        pesoDeFacturabilidade = 100;
        pesoDeOcupacao = 0;
        pesoDePatsDentroDoPrazo = 0;
        pesoDePatsReabertos = 0;
        pesoDeNps = 0;

    }

    // ===== Notas parciais (inicializadas a 0, tal como o Double por omissão em VB.NET) =====
    let notaDeFacturabilidade = 0;
    let notaDeOcupacao = 0;
    let notaDePatsDentroPrazo = 0;
    let notaDePatsReabertos = 0;
    let notaDeNps = 0;

    if (horas > 0) {

        const ocupacaoEsperada = estatisticaDoPerformance["ocpesp"];
        const patsEntrados = estatisticaDoPerformance["pats"];

        const patsDentroDoPrazo = estatisticaDoPerformance["dentro"] / (patsEntrados === 0 ? 1 : patsEntrados);
        const patsReabertos = estatisticaDoPerformance["reabertos"] / (patsEntrados === 0 ? 1 : patsEntrados);
        const patsClassificados = estatisticaDoPerformance["patsclassif"];
        const npsDiff = estatisticaDoPerformance["npsdiff"];

        const nps = npsDiff / (patsClassificados === 0 ? 1 : patsClassificados);
        const ocupacao = horas / (ocupacaoEsperada === 0 ? 1 : ocupacaoEsperada);
        const facturabilidade = facturacao / (ocupacaoEsperada === 0 ? 1 : ocupacaoEsperada);

        notaDeFacturabilidade = (facturabilidade / facturabilidadeStandard) * pesoDeFacturabilidade;
        notaDeOcupacao = (ocupacao / ocupacaoStandard) * pesoDeOcupacao;
        notaDePatsDentroPrazo = (patsDentroDoPrazo / patsDentroPrazoStandard) * pesoDePatsDentroDoPrazo;

        // Nota: se patsReabertos > patsReabertosStandard, notaDePatsReabertos
        // mantém-se a 0 (mesmo comportamento implícito do VB.NET original)
        if (patsReabertos <= patsReabertosStandard) {
            notaDePatsReabertos = 1 * pesoDePatsReabertos;
        }

        notaDeNps = (nps / npsStandard) * pesoDeNps;
    }

    const nota = Math.round(
        ((notaDeFacturabilidade + notaDeOcupacao + notaDePatsDentroPrazo + notaDePatsReabertos + notaDeNps) / 10)
        * 100
    ) / 100; // arredondamento a 2 casas decimais, equivalente a Math.Round(x, 2)

    return nota;
}
